/// <summary>
/// Event handler calls for report extension for Print management document reports
/// </summary>
/// <param name="_docType"></param>
/// <param name="_result"></param>
[SubscribesTo(classStr(PrintMgmtDocType), delegateStr(PrintMgmtDocType, getDefaultReportFormatDelegate))]
public static void PrintMgmtDocType_getDefaultReportFormatDelegate(PrintMgmtDocumentType _docType, EventHandlerResult _result)
{
    if(curExt() == "O014")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::PurchaseOrderPackingSlip:
                _result.result(ssrsReportStr(ETGPurchPackingSlip, Report_O014));
                break;
        }
    }
    else
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::PurchaseOrderPackingSlip:
                _result.result(ssrsReportStr(ETGPurchPackingSlip, ETGTradingReport));
                break;
        }
    }
}
